 925→        "  OR `in` IN (SELECT VALUE id FROM git_commit WHERE workspace = $workspace)",
 926→        ")",
 927→        "ORDER BY extracted_at DESC",
 928→        "LIMIT 40;",
 929→      ].join(" "),
 930→      {
