 953→        "SELECT id, conversation FROM message WHERE id IN $ids;",
 954→        { ids: messageProvenanceRows.map((r) => r.in) },
 955→      )
 956→      .collect<[Array<{ id: RecordId<"message", string>; conversation: RecordId<"conversation", string> }>]>();
 957→    convMap = new Map(convRows.map((r) => [r.id.id as string, r.conversation.id as string]));
 958→  }
 959→
 960→  const provenance = provenanceRows.map((row) => ({
 961→    sourceId: toRecordIdString(row.in),
 962→    sourceKind: row.in.table.name === "document_chunk"
 963→      ? "document_chunk"
 964→      : row.in.table.name === "git_commit"
