 966→        : "message",
 967→    confidence: row.confidence,
 968→    extractedAt: toIsoString(row.extracted_at),
 969→    ...(row.in.table.name === "message" && convMap?.get(row.in.id as string)
 970→      ? { conversationId: convMap.get(row.in.id as string) }
 971→      : {}),
 972→    ...(row.evidence ? { evidence: row.evidence } : {}),
 973→    ...(row.evidence_source ? { evidenceSource: toRecordIdString(row.evidence_source) } : {}),
 974→    ...(row.resolved_from ? { resolvedFrom: toRecordIdString(row.resolved_from) } : {}),
