 984→      kind: table,
 985→      name,
 986→      data: row,
 987→      ...(attribution?.actorType ? { identityType: attribution.actorType } : {}),
 988→      ...(attribution ? { attribution } : {}),
 989→    },
 990→    relationships,
 991→    provenance,
 992→  };
 993→}
