import type { EntityKind } from "../../../shared/contracts";
import { EntityBadge } from "../ui/entity-badge";
import { StatusBadge } from "../ui/status-badge";

type EntityKindSectionProps = {
  kind: EntityKind;
  data: Record<string, unknown>;
  onEntityClick?: (entityId: string) => void;
};

const EVIDENCE_KINDS = new Set<EntityKind>(["observation", "learning", "git_commit", "intent"]);

function ObservationSection({ data }: { data: Record<string, unknown> }) {
  const text = data.text as string | undefined;
  const severity = data.severity as string | undefined;
  const status = data.status as string | undefined;
  const sourceAgent = data.source_agent as string | undefined;
  const observationType = data.observation_type as string | undefined;

  return (
    <div className="flex flex-col gap-1 px-4">
      <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Observation</h4>
      {text ? <p className="text-xs leading-relaxed text-card-foreground">{text}</p> : undefined}
      <dl className="grid grid-cols-[auto_1fr] gap-x-3 gap-y-1 text-xs">
        {severity ? (
          <>
            <dt className="text-muted-foreground">Severity</dt>
            <dd><StatusBadge status={severity} /></dd>
          </>
        ) : undefined}
        {status ? (
          <>
            <dt className="text-muted-foreground">Status</dt>
            <dd><StatusBadge status={status} /></dd>
          </>
        ) : undefined}
        {observationType ? (
          <>
            <dt className="text-muted-foreground">Type</dt>
            <dd className="text-foreground">{observationType}</dd>
          </>
        ) : undefined}
        {sourceAgent ? (
          <>
            <dt className="text-muted-foreground">Source Agent</dt>
            <dd className="text-foreground">{sourceAgent}</dd>
          </>
        ) : undefined}
      </dl>
    </div>
  );
}

function LearningSection({ data }: { data: Record<string, unknown> }) {
  const text = data.text as string | undefined;
  const learningType = data.learning_type as string | undefined;
  const status = data.status as string | undefined;
  const source = data.source as string | undefined;

  return (
    <div className="flex flex-col gap-1 px-4">
      <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Learning</h4>
      {text ? <p className="text-xs leading-relaxed text-card-foreground">{text}</p> : undefined}
      <dl className="grid grid-cols-[auto_1fr] gap-x-3 gap-y-1 text-xs">
        {learningType ? (
          <>
            <dt className="text-muted-foreground">Type</dt>
            <dd className="text-foreground">{learningType}</dd>
          </>
        ) : undefined}
        {status ? (
          <>
            <dt className="text-muted-foreground">Status</dt>
            <dd><StatusBadge status={status} /></dd>
          </>
        ) : undefined}
        {source ? (
          <>
            <dt className="text-muted-foreground">Source</dt>
            <dd className="text-foreground">{source}</dd>
          </>
        ) : undefined}
      </dl>
    </div>
  );
}

function GitCommitSection({ data }: { data: Record<string, unknown> }) {
  const message = data.message as string | undefined;
  const sha = data.sha as string | undefined;
  const authorName = data.author_name as string | undefined;
  const repository = data.repository as string | undefined;

  const truncatedSha = sha ? sha.slice(0, 7) : undefined;

  return (
    <div className="flex flex-col gap-1 px-4">
      <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Commit</h4>
      {message ? <p className="text-xs leading-relaxed text-card-foreground">{message}</p> : undefined}
      <dl className="grid grid-cols-[auto_1fr] gap-x-3 gap-y-1 text-xs">
        {truncatedSha ? (
          <>
            <dt className="text-muted-foreground">SHA</dt>
            <dd className="font-mono text-foreground">{truncatedSha}</dd>
          </>
        ) : undefined}
        {authorName ? (
          <>
            <dt className="text-muted-foreground">Author</dt>
            <dd className="text-foreground">{authorName}</dd>
          </>
        ) : undefined}
        {repository ? (
          <>
            <dt className="text-muted-foreground">Repository</dt>
            <dd className="text-foreground">{repository}</dd>
          </>
        ) : undefined}
      </dl>
    </div>
  );
}

function parseEvidenceRef(ref: unknown): { table: string; id: string } {
  if (typeof ref === "string") {
    const colonIdx = ref.indexOf(":");
    if (colonIdx === -1) return { table: "unknown", id: ref };
    const table = ref.slice(0, colonIdx);
    const rawId = ref.slice(colonIdx + 1).replace(/^[`\u27e8]|[`\u27e9]$/g, "");
    return { table, id: rawId };
  }
  const obj = ref as { tb?: string; id?: string; table?: { name?: string } };
  return {
    table: obj.tb ?? obj.table?.name ?? "unknown",
    id: typeof obj.id === "string" ? obj.id : String(obj.id ?? ""),
  };
}

function EvidenceRefsSection({ refs, onEntityClick }: { refs: unknown[]; onEntityClick?: (entityId: string) => void }) {
  return (
    <div className="flex flex-col gap-1 px-4">
      <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Evidence References</h4>
      <ul className="flex flex-col gap-0.5">
        {refs.map((ref, i) => {
          const { table, id } = parseEvidenceRef(ref);
          return (
            <li key={i}>
              <button
                type="button"
                className="flex items-center gap-1.5 rounded-md px-1.5 py-1 text-left text-xs text-foreground transition-colors hover:bg-hover"
                onClick={() => onEntityClick?.(`${table}:${id}`)}
              >
                <EntityBadge kind={table as EntityKind} />
                <span className="truncate">{id.slice(0, 8)}</span>
              </button>
            </li>
          );
        })}
      </ul>
    </div>
  );
}

function EvidenceVerificationSection({ verification }: { verification: Record<string, unknown> }) {
  const verified = verification.verified_count as number | undefined;
  const total = verification.total_count as number | undefined;
  const mode = verification.enforcement_mode as string | undefined;
  const tierMet = verification.tier_met as boolean | undefined;
  const timeMs = verification.verification_time_ms as number | undefined;
  const authorCount = verification.independent_author_count as number | undefined;
  const failedRefs = verification.failed_refs as string[] | undefined;
  const warnings = verification.warnings as string[] | undefined;

  return (
    <div className="flex flex-col gap-1 px-4">
      <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Evidence Verification</h4>
      <dl className="grid grid-cols-[auto_1fr] gap-x-3 gap-y-1 text-xs">
        {verified !== undefined && total !== undefined ? (
          <>
            <dt className="text-muted-foreground">Verified</dt>
            <dd className="text-foreground">{verified} / {total}</dd>
          </>
        ) : undefined}
        {mode ? (
          <>
            <dt className="text-muted-foreground">Mode</dt>
            <dd><StatusBadge status={mode} /></dd>
          </>
        ) : undefined}
        {tierMet !== undefined ? (
          <>
            <dt className="text-muted-foreground">Tier Met</dt>
            <dd className={tierMet ? "text-green-500" : "text-red-500"}>{tierMet ? "Yes" : "No"}</dd>
          </>
        ) : undefined}
        {authorCount !== undefined ? (
          <>
            <dt className="text-muted-foreground">Authors</dt>
            <dd className="text-foreground">{authorCount}</dd>
          </>
        ) : undefined}
        {timeMs !== undefined ? (
          <>
            <dt className="text-muted-foreground">Time</dt>
            <dd className="text-foreground">{timeMs}ms</dd>
          </>
        ) : undefined}
      </dl>
      {failedRefs && failedRefs.length > 0 ? (
        <div className="mt-1">
          <p className="text-[10px] font-medium text-red-500">Failed refs:</p>
          {failedRefs.map((r, i) => (
            <p key={i} className="truncate font-mono text-[10px] text-red-400">{r}</p>
          ))}
        </div>
      ) : undefined}
      {warnings && warnings.length > 0 ? (
        <div className="mt-1">
          <p className="text-[10px] font-medium text-yellow-500">Warnings:</p>
          {warnings.map((w, i) => (
            <p key={i} className="text-[10px] text-yellow-400">{w}</p>
          ))}
        </div>
      ) : undefined}
    </div>
  );
}

function IntentSection({ data }: { data: Record<string, unknown> }) {
  const goal = data.goal as string | undefined;
  const status = data.status as string | undefined;
  const priority = data.priority as number | undefined;
  const actionSpec = data.action_spec as { action?: string; provider?: string } | undefined;
  const budgetLimit = data.budget_limit as { amount?: number; currency?: string } | undefined;
  const vetoReason = data.veto_reason as string | undefined;
  const errorReason = data.error_reason as string | undefined;

  return (
    <div className="flex flex-col gap-2 px-4">
      <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Intent</h4>
      {goal ? <p className="text-xs leading-relaxed text-card-foreground">{goal}</p> : undefined}
      <dl className="grid grid-cols-[auto_1fr] gap-x-3 gap-y-1 text-xs">
        {status ? (
          <>
            <dt className="text-muted-foreground">Status</dt>
            <dd><StatusBadge status={status} /></dd>
          </>
        ) : undefined}
        {priority !== undefined ? (
          <>
            <dt className="text-muted-foreground">Priority</dt>
            <dd className="text-foreground">{priority}</dd>
          </>
        ) : undefined}
        {actionSpec?.action ? (
          <>
            <dt className="text-muted-foreground">Action</dt>
            <dd className="text-foreground">{actionSpec.action}</dd>
          </>
        ) : undefined}
        {actionSpec?.provider ? (
          <>
            <dt className="text-muted-foreground">Provider</dt>
            <dd className="text-foreground">{actionSpec.provider}</dd>
          </>
        ) : undefined}
        {budgetLimit?.amount !== undefined ? (
          <>
            <dt className="text-muted-foreground">Budget</dt>
            <dd className="text-foreground">
              {new Intl.NumberFormat(undefined, { style: "currency", currency: budgetLimit.currency ?? "USD" }).format(budgetLimit.amount)}
            </dd>
          </>
        ) : undefined}
      </dl>
      {vetoReason ? (
        <p className="text-xs text-red-400"><span className="font-medium">Veto:</span> {vetoReason}</p>
      ) : undefined}
      {errorReason ? (
        <p className="text-xs text-red-400"><span className="font-medium">Error:</span> {errorReason}</p>
      ) : undefined}
    </div>
  );
}

export function EntityKindSection({ kind, data }: EntityKindSectionProps) {
  if (!EVIDENCE_KINDS.has(kind)) return <></>;

  switch (kind) {
    case "observation": return <ObservationSection data={data} />;
    case "learning": return <LearningSection data={data} />;
    case "git_commit": return <GitCommitSection data={data} />;
    case "intent": {
      const evidenceRefs = data.evidence_refs as unknown[] | undefined;
      const evidenceVerification = data.evidence_verification as Record<string, unknown> | undefined;
      return (
        <>
          <IntentSection data={data} />
          {evidenceRefs && evidenceRefs.length > 0 ? <EvidenceRefsSection refs={evidenceRefs} /> : undefined}
          {evidenceVerification ? <EvidenceVerificationSection verification={evidenceVerification} /> : undefined}
        </>
      );
    }
    default: return <></>;
  }
}

import { useEffect, useState } from "react";
import { useNavigate } from "@tanstack/react-router";
import type { EntityCategory, EntityDetailResponse, EntityKind, EntityPriority } from "../../../shared/contracts";
import { ENTITY_CATEGORIES, ENTITY_PRIORITIES } from "../../../shared/contracts";
import { CategoryBadge } from "./CategoryBadge";
import { EntityBadge } from "../ui/entity-badge";
import { StatusBadge } from "../ui/status-badge";
import { RelationshipList } from "./RelationshipList";
import { ProvenanceSection } from "./ProvenanceSection";
import { AgentStatusSection } from "./AgentStatusSection";
import { DescriptionSection } from "./DescriptionSection";
import { useViewState } from "../../stores/view-state";
import { acceptSuggestion, confirmDecision, convertSuggestion, deferSuggestion, dismissSuggestion, markTaskComplete, overrideDecision, setEntityPriority } from "../../graph/actions";
import { Button } from "../ui/button";
import { Input } from "../ui/input";
import { Separator } from "../ui/separator";
import { X } from "lucide-react";
import { ReasoningPanel, deriveReasoningSource } from "../reasoning-panel";
import { EntityKindSection } from "./EntityKindSection";

const CONFIRMABLE_STATUSES = new Set(["extracted", "proposed", "provisional", "inferred"]);

const CATEGORY_TO_ENTITY_TYPE: Record<string, "task" | "feature" | "decision" | "project"> = {
  optimization: "task",
  risk: "decision",
  opportunity: "feature",
  conflict: "decision",
  missing: "task",
  pivot: "project",
};

export function EntityDetailPanel({
  entityId,
  workspaceId,
  onClose,
  onEntityClick,
}: {
  entityId: string;
  workspaceId: string;
  onClose: () => void;
  onEntityClick: (entityId: string) => void;
}) {
  const [detail, setDetail] = useState<EntityDetailResponse | undefined>();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | undefined>();
  const [actionPending, setActionPending] = useState(false);
  const [showConvertForm, setShowConvertForm] = useState(false);
  const [convertKind, setConvertKind] = useState<"task" | "feature" | "decision" | "project">("task");
  const [convertTitle, setConvertTitle] = useState("");
  const navigateToDiscussEntity = useViewState((s) => s.navigateToDiscussEntity);
  const navigate = useNavigate();

  useEffect(() => {
    setLoading(true);
    setError(undefined);

    fetch(`/api/entities/${encodeURIComponent(entityId)}?workspaceId=${encodeURIComponent(workspaceId)}`)
      .then(async (response) => {
        if (!response.ok) {
          const body = await response.text();
          throw new Error(body);
        }
        return response.json() as Promise<EntityDetailResponse>;
      })
      .then((data) => {
        setDetail(data);
        setLoading(false);
      })
      .catch((err) => {
        setError(err instanceof Error ? err.message : "Failed to load entity");
        setLoading(false);
      });
  }, [entityId, workspaceId]);

  function handleJumpToMessage(messageId: string, conversationId?: string) {
    if (conversationId) {
      void navigate({ to: "/chat/$conversationId", params: { conversationId }, search: { message: messageId } });
    } else {
      void navigate({ to: "/chat", search: { message: messageId } });
    }
  }

  async function handleConfirm() {
    if (!detail || actionPending) return;
    setActionPending(true);
    try {
      await confirmDecision(workspaceId, entityId);
      setDetail((prev) =>
        prev
          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "confirmed" } } }
          : prev,
      );
    } finally {
      setActionPending(false);
    }
  }

  async function handleOverride() {
    if (!detail || actionPending) return;
    const newSummary = window.prompt("New decision summary:");
    if (!newSummary) return;
    setActionPending(true);
    try {
      await overrideDecision(workspaceId, entityId, newSummary);
      setDetail((prev) =>
        prev
          ? {
              ...prev,
              entity: {
                ...prev.entity,
                name: newSummary,
                data: { ...prev.entity.data, status: "overridden", summary: newSummary },
              },
            }
          : prev,
      );
    } finally {
      setActionPending(false);
    }
  }

  async function handleComplete() {
    if (!detail || actionPending) return;
    setActionPending(true);
    try {
      await markTaskComplete(workspaceId, entityId);
      setDetail((prev) =>
        prev
          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "done" } } }
          : prev,
      );
    } finally {
      setActionPending(false);
    }
  }

  if (loading) {
    return (
      <aside className="absolute inset-y-0 right-0 z-10 flex w-[340px] flex-col border-l border-border bg-card py-4 animate-in slide-in-from-right">
        <p className="px-4 text-xs text-muted-foreground">Loading...</p>
      </aside>
    );
  }

  if (error || !detail) {
    return (
      <aside className="absolute inset-y-0 right-0 z-10 flex w-[340px] flex-col border-l border-border bg-card py-4 animate-in slide-in-from-right">
        <div className="flex items-start justify-between px-4">
          <p className="text-xs text-muted-foreground">{error ?? "Entity not found"}</p>
          <Button variant="ghost" size="icon-xs" onClick={onClose}><X className="size-3.5" /></Button>
        </div>
      </aside>
    );
  }

  const kind = detail.entity.kind as EntityKind;
  const status = (detail.entity.data.status as string | undefined) ?? "";
  const rationale = detail.entity.data.rationale as string | undefined;

  async function handleSuggestionAction(
    action: (workspaceId: string, entityId: string) => Promise<unknown>,
    resultStatus: string,
  ) {
    if (actionPending) return;
    setActionPending(true);
    try {
      await action(workspaceId, entityId);
      setDetail((prev) =>
        prev ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: resultStatus } } } : prev,
      );
    } finally {
      setActionPending(false);
    }
  }

  const showConfirm = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
  const showOverride = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
  const showComplete = kind === "task" && status !== "done";
  const showSuggestionActions = kind === "suggestion" && (status === "pending" || status === "deferred");

  return (
    <aside className="absolute inset-y-0 right-0 z-10 flex w-[340px] flex-col gap-3 overflow-y-auto border-l border-border bg-card py-4 animate-in slide-in-from-right">
      {/* Header */}
      <div className="flex items-start justify-between gap-2 px-4">
        <div className="flex flex-col gap-1">
          <EntityBadge kind={kind} />
          <h3 className="text-sm font-semibold text-foreground">{detail.entity.name}</h3>
        </div>
        <Button variant="ghost" size="icon-xs" onClick={onClose}><X className="size-3.5" /></Button>
      </div>

      <Separator />

      {/* Metadata */}
      <div className="flex flex-col gap-1 px-4">
        <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Metadata</h4>
        <dl className="grid grid-cols-[auto_1fr] gap-x-3 gap-y-1 text-xs">
          {status ? (
            <>
              <dt className="text-muted-foreground">Status</dt>
              <dd><StatusBadge status={status} /></dd>
            </>
          ) : undefined}
          {typeof detail.entity.data.category === "string" && (ENTITY_CATEGORIES as readonly string[]).includes(detail.entity.data.category) ? (
            <>
              <dt className="text-muted-foreground">Category</dt>
              <dd><CategoryBadge category={detail.entity.data.category as EntityCategory} /></dd>
            </>
          ) : undefined}
          {detail.entity.data.confidence !== undefined ? (
            <>
              <dt className="text-muted-foreground">Confidence</dt>
              <dd className="text-foreground">{(detail.entity.data.confidence as number).toFixed(2)}</dd>
            </>
          ) : undefined}
          {detail.entity.data.created_at ? (
            <>
              <dt className="text-muted-foreground">Created</dt>
              <dd className="text-foreground">{new Date(detail.entity.data.created_at as string).toLocaleDateString()}</dd>
            </>
          ) : undefined}
          {detail.entity.data.owner_name ? (
            <>
              <dt className="text-muted-foreground">Owner</dt>
              <dd className="text-foreground">{detail.entity.data.owner_name as string}</dd>
            </>
          ) : undefined}
          {(kind === "task" || kind === "decision" || kind === "question") ? (
            <>
              <dt className="text-muted-foreground">Priority</dt>
              <dd>
                <select
                  className="h-6 rounded-md border border-input bg-background px-1.5 text-xs text-foreground focus:border-ring focus:outline-none"
                  value={(detail.entity.data.priority as string | undefined) ?? ""}
                  disabled={actionPending}
                  onChange={async (e) => {
                    const value = e.target.value as EntityPriority;
                    if (!value) return;
                    setActionPending(true);
                    try {
                      await setEntityPriority(workspaceId, entityId, value);
                      setDetail((prev) =>
                        prev
                          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, priority: value } } }
                          : prev,
                      );
                    } finally {
                      setActionPending(false);
                    }
                  }}
                >
                  <option value="" disabled>—</option>
                  {ENTITY_PRIORITIES.map((p) => (
                    <option key={p} value={p}>{p}</option>
                  ))}
                </select>
              </dd>
            </>
          ) : undefined}
        </dl>
      </div>

      {kind === "task" ? (
        <AgentStatusSection
          entityId={entityId}
          workspaceId={workspaceId}
          entityKind={kind}
          entityStatus={status}
          agentSession={detail.agentSession}
        />
      ) : undefined}

      <DescriptionSection data={detail.entity.data} kind={kind} onEntityClick={onEntityClick} />

      <EntityKindSection kind={kind} data={detail.entity.data} />

      {rationale ? (
        <div className="flex flex-col gap-1 px-4">
          <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Rationale</h4>
          <p className="text-xs text-muted-foreground">{rationale}</p>
        </div>
      ) : undefined}

      {(() => {
        const reasoningSource = deriveReasoningSource(kind, detail.entity.data);
        return reasoningSource ? <ReasoningPanel source={reasoningSource} /> : undefined;
      })()}

      <RelationshipList relationships={detail.relationships} onEntityClick={onEntityClick} />

      <ProvenanceSection provenance={detail.provenance} onJumpToMessage={handleJumpToMessage} />

      <Separator />

      {/* Actions */}
      <div className="flex flex-wrap gap-1.5 px-4">
        <Button
          variant="outline"
          size="xs"
          onClick={() => {
            navigateToDiscussEntity({
              id: entityId,
              kind,
              name: detail.entity.name,
              ...(status ? { status } : {}),
            });
            void navigate({ to: "/chat" });
          }}
        >
          Discuss
        </Button>
        {showConfirm ? (
          <Button variant="outline" size="xs" disabled={actionPending} onClick={handleConfirm}>
            Confirm
          </Button>
        ) : undefined}
        {showOverride ? (
          <Button variant="outline" size="xs" disabled={actionPending} onClick={handleOverride}>
            Override
          </Button>
        ) : undefined}
        {showComplete ? (
          <Button variant="outline" size="xs" disabled={actionPending} onClick={handleComplete}>
            Mark Complete
          </Button>
        ) : undefined}
        {showSuggestionActions ? (
          <>
            <Button variant="outline" size="xs" disabled={actionPending} onClick={() => handleSuggestionAction(acceptSuggestion, "accepted")}>Accept</Button>
            <Button variant="outline" size="xs" disabled={actionPending} onClick={() => {
              const category = (detail.entity.data.category as string) ?? "";
              setConvertKind(CATEGORY_TO_ENTITY_TYPE[category] ?? "task");
              setConvertTitle(detail.entity.name);
              setShowConvertForm(true);
            }}>Convert</Button>
            <Button variant="outline" size="xs" disabled={actionPending} onClick={() => handleSuggestionAction(deferSuggestion, "deferred")}>Defer</Button>
            <Button variant="destructive" size="xs" disabled={actionPending} onClick={() => handleSuggestionAction(dismissSuggestion, "dismissed")}>Dismiss</Button>
          </>
        ) : undefined}
      </div>

      {showConvertForm ? (
        <div className="flex flex-col gap-2 px-4">
          <label className="flex flex-col gap-1 text-xs text-muted-foreground">
            Convert to:
            <select
              className="h-7 rounded-md border border-input bg-background px-2 text-xs text-foreground focus:border-ring focus:outline-none"
              value={convertKind}
              onChange={(e) => setConvertKind(e.target.value as typeof convertKind)}
            >
              <option value="task">Task</option>
              <option value="feature">Feature</option>
              <option value="decision">Decision</option>
              <option value="project">Project</option>
            </select>
          </label>
          <label className="flex flex-col gap-1 text-xs text-muted-foreground">
            Title:
            <Input
              type="text"
              value={convertTitle}
              onChange={(e) => setConvertTitle(e.target.value)}
              className="h-7 text-xs"
            />
          </label>
          <div className="flex gap-1.5">
            <Button size="xs" disabled={actionPending || !convertTitle.trim()} onClick={async () => {
              setActionPending(true);
              try {
                await convertSuggestion(workspaceId, entityId, convertKind, convertTitle.trim() || undefined);
                setDetail((prev) => prev ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "converted" } } } : prev);
                setShowConvertForm(false);
              } finally { setActionPending(false); }
            }}>Confirm</Button>
            <Button variant="ghost" size="xs" onClick={() => setShowConvertForm(false)}>Cancel</Button>
          </div>
        </div>
      ) : undefined}
    </aside>
  );
}

