944:DEFINE FUNCTION fn::workspace_entity_ids($ws: record<workspace>) {
945-  LET $projects = (SELECT VALUE out FROM has_project WHERE `in` = $ws);
946-  LET $project_features = (SELECT VALUE out FROM has_feature WHERE `in` IN $projects);
947-  -- Include features that are workspace-scoped but not yet linked to a project.
948-  LET $workspace_features = (SELECT VALUE id FROM feature WHERE workspace = $ws);
949-  LET $features = array::distinct($project_features + $workspace_features);
950-  LET $feature_tasks = (SELECT VALUE out FROM has_task WHERE `in` IN $features);
951-  -- Include tasks that are workspace-scoped even if they are only attached via belongs_to.
952-  LET $workspace_tasks = (SELECT VALUE id FROM task WHERE workspace = $ws);
