956-  LET $provenance = (
957-    SELECT VALUE out FROM extraction_relation
958-    WHERE `in` IN (
959-      SELECT VALUE id FROM message
960-      WHERE conversation IN (
961-        SELECT VALUE id FROM conversation WHERE workspace = $ws
962-      )
963-    )
964-  );
965-  LET $policies = (SELECT VALUE `in` FROM protects WHERE out = $ws AND `in`.status IN ['active', 'testing']);
966-  LET $intents = (SELECT VALUE id FROM intent WHERE workspace = $ws AND status NOT IN ['completed', 'vetoed', 'failed']);
967-  LET $agent_sessions = (SELECT VALUE out FROM gates WHERE `in` IN $intents);
968-  LET $objectives = (SELECT VALUE out FROM has_objective WHERE `in` = $ws OR `in` IN $projects);
969-  LET $behaviors = (SELECT VALUE id FROM behavior WHERE workspace = $ws);

