import { RecordId } from "surrealdb";
import { jsonError, jsonResponse } from "../http/response";
import { buildWorkspaceOverview, buildProjectContext, buildTaskContext } from "./context-builder";
import { resolveIntentContext, type IntentContextInput } from "./intent-context";
import { authenticateAndAuthorize } from "./mcp-dpop-auth";
import type { DPoPAuthResult } from "../oauth/types";
import type { DPoPVerificationDeps, LookupWorkspace } from "../oauth/dpop-middleware";
import type { LookupIdentity, LookupManager, ResolvedIdentity, ResolvedManager } from "../oauth/identity-lifecycle";
import { checkAuthority, checkAuthorityOrError } from "../iam/authority";
import type { AgentType } from "../tools/types";
import { createTelemetryConfig } from "../telemetry/ai-telemetry";
import { FUNCTION_IDS } from "../telemetry/function-ids";
import {
  listProjectDecisions,
  getTaskDependencyTree,
  listProjectConstraints,
  listRecentChanges,
  createSubtask,
  updateTaskStatus,
  batchCompleteTasksInTransaction,
  logImplementationNote,
  createAgentSession,
  endAgentSession,
  logCommit,
  getPluginTaskContext,
  getPluginProjectContext,
  validateTaskStatus,
  VALID_TASK_STATUSES,
} from "./mcp-queries";
import { createObservation } from "../observation/queries";
import {
  createSuggestion,
  acceptSuggestion,
  dismissSuggestion,
  deferSuggestion,
  convertSuggestion,
} from "../suggestion/queries";
import { OBSERVATION_TYPES, SUGGESTION_CATEGORIES, type ObservationType, type ObservationSeverity, type SuggestionCategory } from "../../shared/contracts";
import {
  createDecisionRecord,
  createQuestionRecord,
  getEntityDetail,
  parseRecordIdString,
  resolveWorkspaceProjectRecord,
  resolveWorkspaceFeatureRecord,
  isEntityInWorkspace,
  type GraphEntityTable,
} from "../graph/queries";
import { searchEntitiesByBm25 } from "../graph/bm25-search";
import type { ServerDependencies } from "../runtime/types";
import { requireRawId } from "./id-format";
import { processCommitTaskRefs } from "./commit-check";
import { generateObject } from "ai";
import { z } from "zod";
import { createIntent, createTrace, updateIntentStatus, getIntentById } from "../intent/intent-queries";
import type { IntentStatus } from "../intent/types";
import { log } from "../telemetry/logger";
import { createSearchRecentChanges, classifyByAge, type ClassifiedChange } from "../proxy/context-injector";

type WorkspaceRow = {
  id: RecordId<"workspace", string>;
  name: string;
};

type ProjectRow = {
  id: RecordId<"project", string>;
  name: string;
};

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

async function parseJsonBody<T>(request: Request): Promise<T | Response> {
  try {
    return (await request.json()) as T;
  } catch {
    return jsonError("invalid JSON body", 400);
  }
}

const ENTITY_TABLES: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "observation", "suggestion"];

function normalizeTokens(value: string): Set<string> {
  return new Set(
    value
      .toLowerCase()
      .replace(/[^a-z0-9\s]/g, " ")
      .split(/\s+/)
      .map((t) => t.trim())
      .filter((t) => t.length > 2),
  );
}

function hasTokenOverlap(a: Set<string>, b: Set<string>): boolean {
  for (const v of a) {
    if (b.has(v)) return true;
  }
  return false;
}

// ---------------------------------------------------------------------------
// Route handlers
// ---------------------------------------------------------------------------

export function createMcpRouteHandlers(deps: ServerDependencies) {
  const { surreal } = deps;

  // ---- Actor type mapping for authority checks ----
  const DEFAULT_AGENT_TYPE: AgentType = "code_agent";

  // ---- DPoP verification deps ----
  const lookupWorkspace: LookupWorkspace = async (workspaceId: string) => {
    const workspaceRecord = new RecordId("workspace", workspaceId);
    const workspace = await surreal.select<{ id: RecordId<"workspace", string>; name: string }>(workspaceRecord);
    if (!workspace) return undefined;

    // Resolve identity from workspace owner via membership
    const [identityRows] = await surreal.query<[Array<{ in: RecordId<"identity", string> }>]>(
      "SELECT in FROM member_of WHERE out = $ws LIMIT 1;",
      { ws: workspaceRecord },
    );
    const identityId = identityRows[0]?.in?.id as string | undefined;
    if (!identityId) return undefined;

    return { name: workspace.name, identityId };
  };

  const lookupIdentity: LookupIdentity = async (identityId: string) => {
    const [rows] = await surreal.query<[Array<{
      identityId: string;
      identityType: string;
      identityStatus?: string;
      managedBy?: string;
      revokedAt?: string;
    }>]>(
      `SELECT meta::id(id) AS identityId, type AS identityType, identity_status AS identityStatus, managed_by AS managedBy, revoked_at AS revokedAt FROM $identity;`,
      { identity: new RecordId("identity", identityId) },
    );
    const row = rows[0];
    if (!row) return undefined;
    return {
      identityId: row.identityId,
      identityType: row.identityType as ResolvedIdentity["identityType"],
      identityStatus: (row.identityStatus ?? "active") as ResolvedIdentity["identityStatus"],
      managedBy: row.managedBy,
      revokedAt: row.revokedAt ? new Date(row.revokedAt) : undefined,
    };
  };

  const lookupManager: LookupManager = async (managerId: string) => {
    const [rows] = await surreal.query<[Array<{ identityStatus?: string }>]>(
      `SELECT identity_status AS identityStatus FROM identity WHERE meta::id(id) = $managerId LIMIT 1;`,
      { managerId },
    );
    const row = rows[0];
    if (!row) return undefined;
    return {
      identityId: managerId,
      identityStatus: (row.identityStatus ?? "active") as ResolvedManager["identityStatus"],
    };
  };

  const dpopDeps: DPoPVerificationDeps = {
    asSigningKey: deps.asSigningKey,
    nonceCache: deps.nonceCache,
    lookupWorkspace,
    lookupIdentity,
    lookupManager,
  };

  // ---- Auth helper: DPoP + RAR verification ----
  async function requireAuth(request: Request): Promise<DPoPAuthResult | Response> {
    return authenticateAndAuthorize(request, dpopDeps);
  }

  // ---- Workspace helper (no auth - for legacy/unauthenticated routes) ----
  async function resolveWorkspaceById(workspaceId: string): Promise<{ workspaceRecord: RecordId<"workspace", string>; workspace: WorkspaceRow } | Response> {
    const workspaceRecord = new RecordId("workspace", workspaceId);
    const workspace = await surreal.select<WorkspaceRow>(workspaceRecord);
    if (!workspace) return jsonError("workspace not found", 404);
    return { workspaceRecord, workspace };
  }

  async function requireScopedRecord(record: RecordId<string, string>, workspaceRecord: RecordId<"workspace", string>, label: string): Promise<Response | undefined> {
    if (record.table.name === "agent_session") {
      const session = await surreal.select<{ workspace: RecordId<"workspace", string> }>(record as RecordId<"agent_session", string>);
      if (!session) {
        return jsonError(`${label} not found`, 404);
      }
      if ((session.workspace.id as string) !== (workspaceRecord.id as string)) {
        return jsonError(`${label} is outside workspace scope`, 404);
      }
      return undefined;
    }

    const scoped = await isEntityInWorkspace(surreal, workspaceRecord, record as RecordId<GraphEntityTable, string>);
    if (!scoped) {
      return jsonError(`${label} is outside workspace scope`, 404);
    }
    return undefined;
  }

  // =========================================================================
  // Setup
  // =========================================================================

  /** GET /api/mcp/:workspaceId/projects — List workspace projects */
  async function handleListProjects(workspaceId: string): Promise<Response> {
    const result = await resolveWorkspaceById(workspaceId);
    if (result instanceof Response) return result;

    const [projectRows] = await surreal
      .query<[ProjectRow[]]>(
        "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
        { workspace: result.workspaceRecord },
      )
      .collect<[ProjectRow[]]>();

    return jsonResponse({
      workspace: { id: workspaceId, name: result.workspace.name },
      projects: projectRows.map((p) => ({ id: p.id.id as string, name: p.name })),
    }, 200);
  }

  // =========================================================================
  // Tier 1 — Read
  // =========================================================================

  /** POST /api/mcp/:workspaceId/workspace-context — Lightweight orientation (no required params) */
  async function handleWorkspaceContext(workspaceId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;


    const body = await parseJsonBody<{ session_id?: string }>(request);
    if (body instanceof Response) return body;

    try {
      const overview = await buildWorkspaceOverview({
        surreal,
        workspaceRecord: auth.workspaceRecord,
        workspaceName: auth.workspaceName,
        ...(body.session_id ? { excludeSessionId: requireRawId(body.session_id, "session_id") } : {}),
      });
      log.info("mcp.workspace-context.built", "Workspace overview assembled", { workspaceId, projectCount: overview.projects.length });
      return jsonResponse(overview, 200);
    } catch (error) {
      log.error("mcp.workspace-context.failed", "Failed to build workspace overview", error);
      return jsonError("failed to build workspace overview", 500);
    }
  }

  /** POST /api/mcp/:workspaceId/context — Intent-based context resolution */
  async function handleIntentContext(workspaceId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;

    const body = await parseJsonBody<IntentContextInput>(request);
    if (body instanceof Response) return body;

    if (!body.intent || typeof body.intent !== "string") {
      return jsonError("intent is required", 400);
    }

    try {
      const result = await resolveIntentContext({
        surreal,
        workspaceRecord: auth.workspaceRecord,
        workspaceName: auth.workspaceName,
        intent: body.intent,
        cwd: body.cwd,
        paths: body.paths,
      });

      // 04-03: Search recent graph changes and classify by similarity
      let urgentUpdates: Array<{ entity_id: string; entity_type: string; change_description: string; similarity: number; level: "urgent" | "update" }> = [];
      let contextUpdates: Array<{ entity_id: string; entity_type: string; change_description: string; similarity: number; level: "urgent" | "update" }> = [];

      try {
        // Read last_request_at FIRST, then update — otherwise we search "since now" and find nothing.
        let lastRequestAt = new Date(Date.now() - 24 * 60 * 60 * 1000);
        if (body.session_id) {
          const sessionRecord = new RecordId("agent_session", body.session_id);
          const [sessionRows] = await surreal
            .query<[Array<{ last_request_at?: string }>]>(
              `SELECT last_request_at FROM $sess;`,
              { sess: sessionRecord },
            )
            .collect<[Array<{ last_request_at?: string }>]>();
          if (sessionRows[0]?.last_request_at) {
            lastRequestAt = new Date(sessionRows[0].last_request_at);
          }
        }

        const searchRecentChanges = createSearchRecentChanges(surreal);
        const candidates = await searchRecentChanges(body.intent, workspaceId, lastRequestAt);

        // Update agent_session.last_request_at AFTER search (04-02)
        if (body.session_id) {
          const sessionRecord = new RecordId("agent_session", body.session_id);
          deps.inflight.track(
            surreal.query(
              `UPDATE $sess SET last_request_at = time::now();`,
              { sess: sessionRecord },
            ).catch(() => undefined),
          );
        }
        const classified = classifyByAge(candidates, new Date());

        function toUpdateItem(change: ClassifiedChange) {
          return {
            entity_id: change.id,
            entity_type: change.table,
            change_description: change.text,
            similarity: change.similarity,
            level: (change.classification === "urgent-context" ? "urgent" : "update") as "urgent" | "update",
          };
        }

        urgentUpdates = classified
          .filter((c) => c.classification === "urgent-context")
          .map(toUpdateItem);
        contextUpdates = classified
          .filter((c) => c.classification === "context-update")
          .map(toUpdateItem);
      } catch (error) {
        log.warn("mcp.intent-context.recent-changes-failed", "Failed to search recent changes", {
          error: error instanceof Error ? error.message : String(error),
        });
      }

      log.info("mcp.intent-context.resolved", "Intent context resolved", {
        workspaceId, level: result.level,
        urgentCount: urgentUpdates.length, contextCount: contextUpdates.length,
      });
      return jsonResponse({ ...result, urgent_updates: urgentUpdates, context_updates: contextUpdates }, 200);
    } catch (error) {
      log.error("mcp.intent-context.failed", "Failed to resolve intent context", error);
      return jsonError("failed to resolve intent context", 500);
    }
  }

  /** POST /api/mcp/:workspaceId/project-context — Full project context (project_id required) */
  async function handleProjectContext(workspaceId: string, request: Request): Promise<Response> {
