// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

async function parseJsonBody<T>(request: Request): Promise<T | Response> {
  try {
    return (await request.json()) as T;
  } catch {
    return jsonError("invalid JSON body", 400);
  }
}

const ENTITY_TABLES: GraphEntityTable[] = ["workspace", "project", "person", "identity", "feature", "task", "decision", "question", "observation", "suggestion", "policy", "intent", "agent_session", "objective", "behavior", "learning", "git_commit"];

function normalizeTokens(value: string): Set<string> {
  return new Set(
    value
      .toLowerCase()
      .replace(/[^a-z0-9\s]/g, " ")
      .split(/\s+/)
      .map((t) => t.trim())
      .filter((t) => t.length > 2),
  );
}

function hasTokenOverlap(a: Set<string>, b: Set<string>): boolean {
  for (const v of a) {
    if (b.has(v)) return true;
  }
  return false;
}

